#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <WiFi.h>
#include <HTTPClient.h>

#define WIFI_SSID getenv("WIFI_SSID")
#define WIFI_PASSWORD getenv("WIFI_PASSWORD")
#define API_KEY getenv("API_KEY")
#define CLOUD_SERVICE_URL "https://api.example.com/upload"

void setup() {
    Serial.begin(115200);
    connectToWiFi();
}

void loop() {
    // Capture image and upload to cloud
    uploadImage();
    delay(60000); // Wait for 1 minute before next upload
}

void connectToWiFi() {
    Serial.print("Connecting to WiFi");
    WiFi.begin(WIFI_SSID, WIFI_PASSWORD);
    
    while (WiFi.status() != WL_CONNECTED) {
        delay(1000);
        Serial.print(".");
    }
    
    Serial.println("Connected to WiFi");
}

void uploadImage() {
    // Simulate image capture
    const char* imageData = "image_data"; // Replace with actual image capture logic

    if (WiFi.status() == WL_CONNECTED) {
        HTTPClient http;
        http.begin(CLOUD_SERVICE_URL);
        http.addHeader("Content-Type", "application/json");
        http.addHeader("Authorization", API_KEY);

        String payload = "{\"image\":\"";
        payload += imageData;
        payload += "\"}";

        int httpResponseCode = http.POST(payload);
        if (httpResponseCode > 0) {
            String response = http.getString();
            Serial.println(httpResponseCode);
            Serial.println(response);
        } else {
            Serial.print("Error on sending POST: ");
            Serial.println(httpResponseCode);
        }
        http.end();
    } else {
        Serial.println("WiFi not connected");
    }
}